// ============================================================================
// Scroll Position Cache Entry
// ============================================================================

// LIFETIME CONTRACT: The scroll cache stores raw TextDocument* pointers.
// Documents must outlive the editor, or be explicitly removed from cache
// before destruction. If a document is destroyed while cached, the cache
// entry becomes a dangling pointer. Currently, the caller (dialog/view)
// is responsible for ensuring document lifetime exceeds editor lifetime.
// If pointer reuse becomes an issue, consider using a monotonic document ID.

struct ScrollCacheEntry {
    TextDocument* document = nullptr;
    float scroll_x = 0.0f;
    float scroll_y = 0.0f;
};

// ============================================================================
// Scrollbar Hover State
// ============================================================================

enum class ScrollbarHover {
    None,
    UpButton,
    DownButton,
    Thumb,
    Track
};

